import{_ as o,o as t,c as a,a3 as i}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"80. Public Holidays","description":"","frontmatter":{"title":"80. Public Holidays","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","public-holidays","preliminary"]},"headers":[],"relativePath":"ebas/mspp/leave/80-public-holidays.md","filePath":"ebas/mspp/leave/80-public-holidays.md"}'),r={name:"ebas/mspp/leave/80-public-holidays.md"};function n(l,e,s,h,p,d){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="_80-public-holidays" tabindex="-1">80. Public Holidays <a class="header-anchor" href="#_80-public-holidays" aria-label="Permalink to &quot;80. Public Holidays&quot;">​</a></h1><p><strong>80.1</strong> Entitlement to paid time off</p><p><strong>a.</strong> An Employee shall be entitled to paid time off (or public holiday payments for time worked) in respect of public holidays in accordance with this clause.</p><p><strong>b.</strong> The public holidays to which this clause applies are the days determined under Victorian law as public holidays in respect of the following occasions:</p><p><strong>(i)</strong> New Year’s Day, Good Friday, the Saturday immediately before Easter Sunday, Easter Monday, Christmas Day and Boxing Day; and</p><p><strong>(ii)</strong> Australia Day, Anzac Day, Queen’s Birthday, Labour Day; and,</p><p><strong>(iii)</strong> The Friday before the AFL Grand Final; and</p><p><strong>(iv)</strong> Melbourne Cup Day or in lieu of Melbourne Cup Day, some other day as determined in a particular locality; and</p><p><strong>(v)</strong> any additional public holiday declared or prescribed in Victoria or a locality in respect of occasions other than those set out in 80.1b(i), 80.1b(ii) or 80.1b(iii).</p><p><strong>c.</strong> If, in a particular year, no day is determined under Victorian law as a public holiday in respect of any occasion referred to in clause 80.1b(i), 80.1b(ii) or 80.1b(iii), a public holiday will be observed on the actual day specified in clause 80.1b(i), 80.1b(ii) or 80.1b(iii).</p><p><strong>80.2</strong> Payment For Work On Public Holidays When Additional/Other Days Are Declared</p><p><strong>a.</strong> The following rules regarding public holiday penalties will apply in circumstances where, Christmas Day, Australia Day, Boxing Day, or New Year&#39;s Day (Actual Day) is a Saturday or a Sunday, and a substitute or additional public holiday is determined under Victorian law on another day in respect of any of those occasions (Other Day):</p><p><strong>(i)</strong> If an Employee works on both the Actual Day and the Other Day, week-end penalties shall apply to time worked on the Actual Day and public holiday penalties shall apply to time worked on the Other Day.</p><p><strong>(ii)</strong> If an Employee works on the Other Day and not the Actual Day, the Employee will receive public holiday entitlements for time worked on the Other Day.</p><p><strong>(iii)</strong> If an Employee works on the Actual Day and not the Other Day, public holiday penalties (but not weekend penalties) shall apply to the Actual Day.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>(iv)</strong> The Employee shall only receive the public holiday penalties for either the Actual Day or the Other Day, but not both.</p><p><strong>80.3</strong> Public Holiday Pay For Part Time Staff Rostered Off</p><p><strong>a.</strong> To determine the entitlement to public holidays for part-timers rostered off on a public holiday the following shall apply:</p><p><strong>(i)</strong> Where a public holiday occurs on a day a part-time Employee normally works, but the Employee is not required to work, the Employee is entitled to receive the public holiday benefit as prescribed by clause 80.1.</p><p><strong>(ii)</strong> Where a public holiday occurs on a day a part-time Employee is not rostered to work the Employee shall receive payment according to the formula in clause 80.3(iii).</p><p><strong>(iii)</strong> Average weekly hours over the previous six months are to be determined and a pro-rata payment made, regardless of whether the Employee would ever work on that day of the week. Example: Average Shift Length Base Penalty Payment Hours Payment 24/38 hours X 8 hours (Where 5.05 hours T 1.0 5.05 the ordinary shift length is 8 hours) 20/38 hours X 10 hours 5.26 T1.0 5.26 hours (Where the ordinary shift length is 10 hours)</p><p><strong>b.</strong> A part-time Employee who is only ever employed on a day or days between Monday and Friday (inclusive), will not receive any entitlement for a public holiday falling on a Saturday or Sunday. If an additional day or substitute day is declared on a weekday in respect to the relevant Saturday or Sunday, this exclusion will not affect the benefits applicable to the additional day or substitute day.</p><p><strong>80.4</strong> Substitution of one public holiday for another</p><p><strong>a.</strong> An Employer and Employee may agree to substitute another day for a day that would otherwise be a public holiday under the NES or this Agreement.</p><p><strong>b.</strong> An Employer and Employee may agree to substitute another part-day for a this Agreement.</p><p><strong>c.</strong> Where an agreement under subclause 80.4a or 80.4b is reached, it will be recorded in writing and a copy given to the Employee.</p><p><strong>80.5</strong> Payment For Time Worked On A Public Holiday</p><p><strong>a.</strong> An Employee, other than a casual Employee, who works (excepting on recall) on a public holiday which applies under clause 80.1 shall:</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>(i)</strong> In addition to being paid for the day at the ordinary rate, be paid for the time so worked, or to take time off in lieu at the appropriate penalty rate, with a minimum of four hours’ wages at the rate of: <strong>(A)</strong> 100% if the public holiday occurs Monday to Friday <strong>(B)</strong> 150% if the public holiday occurs on a Saturday or Sunday; or <strong>(C)</strong> be entitled to time off at equivalent to the hours worked if the public holiday occurs on a Monday to Friday with a minimum of four hours&#39; time off, or amounting to one and a half times the hours worked where the public holiday falls on a weekend with a minimum of six hours&#39; time off without loss of pay; such time off to be taken at a time mutually convenient to the Employer and Employee within one month of the day on which the Employee worked, provided that where an Employee is entitled to a full working day off, such time off work may be added to the Employee’s annual leave by mutual consent.</p><p><strong>b.</strong> Provided that where a pharmacist works overtime on a public holiday which occurs on a weekend, this clause shall prevail over subclause 56.4</p><p><strong>c.</strong> An Employee who is recalled to duty and works on any public holiday which applies under clause 80 shall be paid from the time of receiving the recall until the time of finishing such recall duty with a minimum of three hours&#39; payment for each such recall at the rate of time and a half in addition to the hourly rate for ordinary time under this Agreement.</p><p><strong>d.</strong> A casual Employee who works on a public holiday which applies under clause 80 shall be paid for the time so worked with a minimum of four hours’ wages, inclusive of casual loading, at the rate of:</p><p><strong>(i)</strong> 250% if the public holiday occurs Monday to Friday</p><p><strong>(ii)</strong> 312.5% if the public holiday occurs on a Saturday or Sunday</p><p><strong>80.6</strong> Public holidays occurring on rostered days off</p><p><strong>a.</strong> Subject to sub-clauses 80.6c below, a full-time Employee shall be entitled to receive one day’s pay in addition to the weekly wage or one day off at a time convenient to the Employer without loss of pay in lieu thereof where such holiday occurs on their rostered day off.</p><p><strong>b.</strong> This subclause does not apply to full-time Employees who normally work Monday to Friday only.</p><p><strong>c.</strong> Where clause 80.2a applies, and:</p><p><strong>(i)</strong> the Employee is rostered off for both the Actual Day and the Other Day(as described in 80.2a), then only one day’s payment will be made under paragraph 80.6a; or</p><p><strong>(ii)</strong> the Employee works only on one of either the Actual Day or Other Day and receives public holiday rates for the day worked, the Employee will not receive a payment under paragraph 80.6a in respect of the day not worked.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>80.7</strong> Public Holiday Night Duty</p><p><strong>a.</strong> An Employee who works on a night shift which begins or ends on a Public Holiday will receive:</p><p><strong>(i)</strong> the Public Holiday penalty rate, for the time worked on the Public Holiday (with a minimum of 4 hours at the public holiday rate in respect of that public holiday); and</p><p><strong>(ii)</strong> the rate which would ordinarily apply, for time worked other than on the public holiday; and</p><p><strong>(iii)</strong> at the pro rata public holiday rostered off benefit for that part of a shift that falls on the public holiday that they are not rostered to work and do not work.</p><p>Plain language terms: public holiday pay, PH pay.</p>',49)])])}const c=o(r,[["render",n]]);export{u as __pageData,c as default};
